// Provide CVA6 configuration via defines to avoid cross-file package ordering issues.
// Defaults below match the CVA6 VCU118 SmallNVDLA configuration.
`ifndef CVA6_CONFIG_RASDEPTH
`define CVA6_CONFIG_RASDEPTH 2
`endif
`ifndef CVA6_CONFIG_BTBENTRIES
`define CVA6_CONFIG_BTBENTRIES 32
`endif
`ifndef CVA6_CONFIG_BHTENTRIES
`define CVA6_CONFIG_BHTENTRIES 128
`endif
`ifndef CVA6_CONFIG_NRPMPENTRIES
`define CVA6_CONFIG_NRPMPENTRIES 8
`endif
`ifndef CVA6_CONFIG_NR_SCOREBOARD_ENTRIES
`define CVA6_CONFIG_NR_SCOREBOARD_ENTRIES 8
`endif
`ifndef CVA6_CONFIG_NR_COMMIT_PORTS
`define CVA6_CONFIG_NR_COMMIT_PORTS 2
`endif
`ifndef CVA6_CONFIG_RENAME_EN
`define CVA6_CONFIG_RENAME_EN 0
`endif
`ifndef CVA6_CONFIG_FPGA_EN
`define CVA6_CONFIG_FPGA_EN 0
`endif
`ifndef CVA6_CONFIG_C_EXT_EN
`define CVA6_CONFIG_C_EXT_EN 1
`endif
`ifndef CVA6_CONFIG_H_EXT_EN
`define CVA6_CONFIG_H_EXT_EN 1
`endif
`ifndef CVA6_CONFIG_F16_EN
`define CVA6_CONFIG_F16_EN 0
`endif
`ifndef CVA6_CONFIG_F16ALT_EN
`define CVA6_CONFIG_F16ALT_EN 0
`endif
`ifndef CVA6_CONFIG_F8_EN
`define CVA6_CONFIG_F8_EN 0
`endif
`ifndef CVA6_CONFIG_FVEC_EN
`define CVA6_CONFIG_FVEC_EN 0
