module apb_to_reg (
  input  logic          clk_i,
  input  logic          rst_ni,

  input  logic          penable_i,
  input  logic          pwrite_i,
  input  logic [31:0]   paddr_i,
  input  logic          psel_i,
  input  logic [31:0]   pwdata_i,
  output logic [31:0]   prdata_o,
  output logic          pready_o,
  output logic          pslverr_o,

  // Explicit REG_BUS ports for Vivado 2019.2 compatibility
  output logic [31:0]   addr_o,
  output logic          write_o,
  output logic [31:0]   wdata_o,
  output logic [3:0]    wstrb_o,
  output logic          valid_o,
  input  logic [31:0]   rdata_i,
  input  logic          error_i,
  input  logic          ready_i
);

  always_comb begin
    addr_o = paddr_i;
    write_o = pwrite_i;
    wdata_o = pwdata_i;
    wstrb_o = '1;
    valid_o = psel_i & penable_i;
    pready_o = ready_i;
    pslverr_o = error_i;
    prdata_o = rdata_i;
  end
endmodule
