`ifdef VERILATOR
  `define IOMMU_CQ_DEBUG
`endif
`ifdef IOMMU_CQ_DEBUG
  // Observe CQ tail writes and current value
  logic [31:0] cqt_q_prev;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      cqt_q_prev <= '0;
    end else begin
      if (cqt_we) begin
        $display("[%0t][CQT] write wdata=0x%0h masked=0x%0h log2sz_1=0x%0h",
                 $time, reg_wdata[31:0], cqt_wd, reg2hw.cqb.log2sz_1.q);
      end
      if (reg2hw.cqt.q != cqt_q_prev) begin
        $display("[%0t][CQT] q changed to 0x%0h", $time, reg2hw.cqt.q);
      end
      cqt_q_prev <= reg2hw.cqt.q;
    end
  end
  // Observe CQCSR writes (enable/IE)
  always_ff @(posedge clk_i) begin
    if (cqcsr_cqen_we || cqcsr_cie_we) begin
      $display("[%0t][CQCSR] cqen_we=%0b cqen_wd=%0b cqen_q=%0b cie_we=%0b cie_wd=%0b cie_q=%0b",
               $time, cqcsr_cqen_we, cqcsr_cqen_wd, reg2hw.cqcsr.cqen.q,
               cqcsr_cie_we, cqcsr_cie_wd, reg2hw.cqcsr.cie.q);
    end
  end
  // Log all regbus writes (addr is byte offset into 4KiB reg window)
  always_ff @(posedge clk_i) begin
    if (reg_we) begin
      $display("[%0t][REGBUS] write addr=0x%0h wdata=0x%0h wstrb=0x%0h", $time, reg_addr, reg_wdata, reg_be);
    end
  end
  // Monitor incoming reg_req_i to confirm valid/write are seen
  always_ff @(posedge clk_i) begin
    if (reg_intf_req.valid) begin
      $display("[%0t][REG_REQ] valid=1 write=%0b addr=0x%0h wdata=0x%0h wstrb=0x%0h",
               $time, reg_intf_req.write, reg_intf_req.addr, reg_intf_req.wdata, reg_intf_req.wstrb);
    end
  end
`endif


