// Author: Manuel Rodríguez <manuel.cederog@gmail.com>
// Date: 15/08/2023
//
// Description: AXI4 Boundary Checker module for RISC-V IOMMU: 
//              Checks whether an AXI transaction crosses a 4-kiB address boundary, 
//              which is illegal in AXI4 transactions.

/* verilator lint_off WIDTH */

module rv_iommu_axi4_bc (
    // AxVALID
    input  logic                    request_i,
    // AxADDR
    input  logic [riscv::VLEN-1:0]  addr_i,
    // AxBURST
    input  axi_pkg::burst_t         burst_type_i,
    // AxLEN
    input  axi_pkg::len_t           burst_length_i,
    // AxSIZE
    input  axi_pkg::size_t          n_bytes_i,

    // To indicate valid requests or boundary violations
    output logic                    allow_request_o,
    output logic                    bound_violation_o
); 

    always_comb begin : boundary_check

        allow_request_o   = 1'b0;
        bound_violation_o = 1'b0;

        // Request received
        if (request_i) begin

            // Consider burst type, N of beats and size of the beat (always 64 bits) to calculate number of bytes accessed:
            case (burst_type_i)

                // BURST_FIXED: The final address is Start Addr + 8 (ex: ARADDR + 8)
                axi_pkg::BURST_FIXED: begin
                    // May be optimized with bitwise AND
                    if (((addr_i & 12'hfff) + (1'b1 << n_bytes_i)) < (1'b1 << 12)) begin
                        allow_request_o   = 1'b1;     // Allow transaction
                    end

                    // Boundary violation
                    else begin
                        bound_violation_o = 1'b1;
                    end
                end

                // BURST_WRAP: The final address is the Wrap Boundary (Lower address) + size of the transfer
                axi_pkg::BURST_WRAP: begin
                    // wrap_boundary = (start_address/(number_bytes*burst_length_i)) * (number_bytes*burst_length_i)
                    // address_n = wrap_boundary + (number_bytes * burst_length_i)
                    logic [riscv::PLEN-1:0] wrap_boundary;

                    // by spec, N of transfers must be {2, 4, 8, 16}
                    // So, ARLEN must be {1, 3, 7, 15}
                    logic [2:0] log2_len;
                    case (burst_length_i)
                        8'd1: log2_len = 3'b001;
                        8'd3: log2_len = 3'b010;
                        8'd7: log2_len = 3'b011;
                        8'd15: log2_len = 3'b100;
                        default: log2_len = 3'b111;  // invalid
                    endcase

                    // The lowest address within a wrapping burst
                    // Wrap_Boundary = (INT(Start_Address / (Burst_Length x Number_Bytes))) x (Burst_Length x Number_Bytes)
                    wrap_boundary = (addr_i >> (log2_len + n_bytes_i)) << (log2_len + n_bytes_i);

                    // Check if the highest address crosses a 4 kiB boundary (Highest Addr - Lower Addr >= 4kiB)
                    // Highest addr_i = Wrap_Boundary + (Burst_Length x Number_Bytes)
                    if (!(&log2_len) && 
                         (((wrap_boundary & 12'hfff) + ((burst_length_i + 1) << n_bytes_i)) < (1'b1 << 12))) begin
                        allow_request_o  = 1'b1;     // Allow transaction
                    end
                    
                    // Boundary violation
                    else begin
                        bound_violation_o = 1'b1;
                    end

                end

                // BURST_INCR: The final address is Start Addr + Burst_Length x Number_Bytes
                axi_pkg::BURST_INCR: begin
                    // check if burst is within 4K range
                    if (((addr_i & 12'hfff) + ((burst_length_i + 1) << n_bytes_i)) < (1'b1 << 12)) begin
                        allow_request_o  = 1'b1;     // Allow transaction
                    end

                    // Boundary violation
                    else begin
                        bound_violation_o = 1'b1;
                    end
                end

                default:;
            endcase
        end
    end
    
endmodule

/* verilator lint_on WIDTH */// Copyright © 2023 Manuel Rodríguez & Zero-Day Labs, Lda.
// SPDX-License-Identifier: Apache-2.0 WITH SHL-2.1

// Licensed under the Solderpad Hardware License v 2.1 (the “License”); 
// you may not use this file except in compliance with the License, 
// or, at your option, the Apache License version 2.0. 
// You may obtain a copy of the License at https://solderpad.org/licenses/SHL-2.1/.
// Unless required by applicable law or agreed to in writing, 
// any work distributed under the License is distributed on an “AS IS” BASIS, 
// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. 
// See the License for the specific language governing permissions and limitations under the License.
//
// Author: Manuel Rodríguez <manuel.cederog@gmail.com>
// Date: 01/03/2023
//
// Description: RISC-V IOMMU Data Structures Interface Wrapper.

module rv_iommu_ds_if #(
    /// AXI Full request struct type
    parameter type  axi_req_t       = logic,
    /// AXI Full response struct type
    parameter type  axi_rsp_t       = logic
) (
    input  logic        clk_i,
    input  logic        rst_ni,

    // External ports: To DS IF Bus
    input  axi_rsp_t    ds_resp_i,
    output axi_req_t    ds_req_o,

    /*--------------------------------------------*/
    
    // From PTW
    output axi_rsp_t    ptw_resp_o,
    input  axi_req_t    ptw_req_i,

    // From CDW
    output axi_rsp_t    cdw_resp_o,
    input  axi_req_t    cdw_req_i,

    // From CQ
    output axi_rsp_t    cq_resp_o,
    input  axi_req_t    cq_req_i,

    // From FQ
    output axi_rsp_t    fq_resp_o,
    input  axi_req_t    fq_req_i,

    // From MSI IG
    output axi_rsp_t    msi_ig_resp_o,
    input  axi_req_t    msi_ig_req_i
);

    logic[1:0] w_select, w_select_fifo;
    // Local widths derived from incoming AXI request structs
    localparam int AR_BITS   = $bits(ptw_req_i.ar);
    localparam int AW_BITS   = $bits(cq_req_i.aw);
    localparam int W_BITS    = $bits(cq_req_i.w);
    localparam int ID_WIDTH  = $bits(cq_req_i.aw.id);

    //# AR Channel (PTW, CDW, CQ)
    // Explicitly align AR data/valid/ready indices; use packed vectors to match arbiter ports
    logic [2:0][AR_BITS-1:0] ar_data;
    logic [2:0]              ar_valid;
    logic [2:0]              ar_ready;
    logic [AR_BITS-1:0]      ar_data_arb;
    assign ar_data [0]  = ptw_req_i.ar;
    assign ar_valid[0]  = ptw_req_i.ar_valid;
    assign ar_data [1]  = cdw_req_i.ar;
    assign ar_valid[1]  = cdw_req_i.ar_valid;
    assign ar_data [2]  = cq_req_i.ar;
    assign ar_valid[2]  = cq_req_i.ar_valid;
    stream_arbiter #(
        .DATA_T ( logic [AR_BITS-1:0] ),
        .N_INP  ( 3                         )
    ) i_stream_arbiter_ar (
        .clk_i          (clk_i),
        .rst_ni         (rst_ni),
        .inp_data_i     ( ar_data ),
        .inp_valid_i    ( ar_valid ),
        .inp_ready_o    ( ar_ready ),
        .oup_data_o     ( ar_data_arb       ),
        .oup_valid_o    ( ds_req_o.ar_valid  ),
        .oup_ready_i    ( ds_resp_i.ar_ready )
    );
    assign ds_req_o.ar = ar_data_arb;
    assign ptw_resp_o.ar_ready = ar_ready[0];
    assign cdw_resp_o.ar_ready = ar_ready[1];
    assign cq_resp_o.ar_ready  = ar_ready[2];

    //# AW Channel (CQ, FQ, MSI IG)
    // Align AW channel ordering explicitly
    logic [2:0][AW_BITS-1:0] aw_data;
    logic [2:0]              aw_valid;
    logic [2:0]              aw_ready;
    logic [AW_BITS-1:0]      aw_data_arb;
    assign aw_data [0]  = cq_req_i.aw;
    assign aw_valid[0]  = cq_req_i.aw_valid;
    assign aw_data [1]  = fq_req_i.aw;
    assign aw_valid[1]  = fq_req_i.aw_valid;
    assign aw_data [2]  = msi_ig_req_i.aw;
    assign aw_valid[2]  = msi_ig_req_i.aw_valid;
    stream_arbiter #(
        .DATA_T ( logic [AW_BITS-1:0] ),
        .N_INP  ( 3                         )
    ) i_stream_arbiter_aw (
        .clk_i          (clk_i),
        .rst_ni         (rst_ni),
        .inp_data_i     ( aw_data ),
        .inp_valid_i    ( aw_valid ),
        .inp_ready_o    ( aw_ready ),
        .oup_data_o     ( aw_data_arb       ),
        .oup_valid_o    ( ds_req_o.aw_valid  ),
        .oup_ready_i    ( ds_resp_i.aw_ready )
    );
    assign ds_req_o.aw = aw_data_arb;
    assign cq_resp_o.aw_ready   = aw_ready[0];
    assign fq_resp_o.aw_ready   = aw_ready[1];
    assign msi_ig_resp_o.aw_ready = aw_ready[2];

    //# W Channel
    // Control signal to select accepted AWID for writing data to W Channel
    always_comb begin
        w_select = '0;
        unique case (ds_req_o.aw.id)
            {ID_WIDTH{1'b0}}:                  w_select = 2'd2; // MSI IG
            {{(ID_WIDTH-4){1'b0}},4'b0001}:    w_select = 2'd1; // FQ
            {{(ID_WIDTH-4){1'b0}},4'b0010}:    w_select = 2'd0; // CQ
            default:                            w_select = 2'd0; // none
        endcase
    end

    // Save AWID whenever a transaction is accepted in AW Channel.
    // While writing data to W Channel, another AW transaction may be accepted, so we need to queue the AWIDs
    // Only CQ, FQ and MSI IG perform writes to memory, so we can have max 3 outstanding transactions
    fifo_v3 #(
      .DATA_WIDTH   ( 2    ),
      // we can have a maximum of 2 oustanding transactions as each port is blocking
      .DEPTH        ( 3    )
    ) i_fifo_w_channel (
      .clk_i      ( clk_i           ),
      .rst_ni     ( rst_ni          ),
      .flush_i    ( 1'b0            ),
      .testmode_i ( 1'b0            ),
      .full_o     (                 ),
      .empty_o    (                 ),
      .usage_o    (                 ),
      .data_i     ( w_select        ),
      .push_i     ( ds_req_o.aw_valid & ds_resp_i.aw_ready ), // a new AW transaction was requested and granted
      .data_o     ( w_select_fifo   ),                          // WID to select the W MUX
      .pop_i      ( ds_req_o.w_valid & ds_resp_i.w_ready & ds_req_o.w.last ) // W transaction has finished
    );

    // For invalid AWIDs for which the request was accepted, or when AW FIFO is empty, CQ channel is selected
    // Multiplex W channel based on accepted AWID
    always_comb begin
        ds_req_o.w       = '0;
        ds_req_o.w_valid = 1'b0;
        cq_resp_o.w_ready    = 1'b0;
        fq_resp_o.w_ready    = 1'b0;
        msi_ig_resp_o.w_ready= 1'b0;
        unique case (w_select_fifo)
            2'd0: begin
                ds_req_o.w       = cq_req_i.w;
                ds_req_o.w_valid = cq_req_i.w_valid;
                cq_resp_o.w_ready = ds_resp_i.w_ready;
            end
            2'd1: begin
                ds_req_o.w       = fq_req_i.w;
                ds_req_o.w_valid = fq_req_i.w_valid;
                fq_resp_o.w_ready = ds_resp_i.w_ready;
            end
            2'd2: begin
                ds_req_o.w       = msi_ig_req_i.w;
                ds_req_o.w_valid = msi_ig_req_i.w_valid;
                msi_ig_resp_o.w_ready = ds_resp_i.w_ready;
            end
            default: begin
                ds_req_o.w       = '0;
                ds_req_o.w_valid = 1'b0;
            end
        endcase
    end

    // Route responses based on ID
    // 0000         -> PTW
    // 0001         -> CDW
    // 0010         -> CQ
    //# R Channel: We only demux RVALID/RREADY signals
    assign ptw_resp_o.r = ds_resp_i.r;
    assign cdw_resp_o.r = ds_resp_i.r;
    assign cq_resp_o.r  = ds_resp_i.r;

    logic [1:0] r_select;

    // Demux RVALID/RREADY signals
    always_comb begin
        r_select = 0;
        unique case (ds_resp_i.r.id)
            {ID_WIDTH{1'b0}}:                r_select = 2; // PTW
            {{(ID_WIDTH-4){1'b0}},4'b0001}:  r_select = 1; // CDW
            {{(ID_WIDTH-4){1'b0}},4'b0010}:  r_select = 0; // CQ
            default:                        r_select = 0;
        endcase
    end

    stream_demux #(
        .N_OUP ( 3 )
    ) i_stream_demux_r (
        .inp_valid_i ( ds_resp_i.r_valid ),
        .inp_ready_o ( ds_req_o.r_ready  ),
        .oup_sel_i   ( r_select           ),
        .oup_valid_o ( {ptw_resp_o.r_valid, cdw_resp_o.r_valid, cq_resp_o.r_valid} ),
        .oup_ready_i ( {ptw_req_i.r_ready, cdw_req_i.r_ready, cq_req_i.r_ready} )
    );

    //# B Channel: We only demux BVALID/BREADY signals
    logic [1:0] b_select;

    assign cq_resp_o.b = ds_resp_i.b;
    assign fq_resp_o.b = ds_resp_i.b;
    assign msi_ig_resp_o.b = ds_resp_i.b;

    always_comb begin
        b_select = 0;
        unique case (ds_resp_i.b.id)
            {ID_WIDTH{1'b0}}:                b_select = 2; // MSI IG
            {{(ID_WIDTH-4){1'b0}},4'b0001}:  b_select = 1; // FQ
            {{(ID_WIDTH-4){1'b0}},4'b0010}:  b_select = 0; // CQ
            default:                        b_select = 0;
        endcase
    end

    stream_demux #(
        .N_OUP ( 3 )
    ) i_stream_demux_b (
        .inp_valid_i ( ds_resp_i.b_valid ),
        .inp_ready_o ( ds_req_o.b_ready  ),
        .oup_sel_i   ( b_select           ),
        .oup_valid_o ( {cq_resp_o.b_valid, fq_resp_o.b_valid, msi_ig_resp_o.b_valid} ),
        .oup_ready_i ( {cq_req_i.b_ready,  fq_req_i.b_ready, msi_ig_req_i.b_ready} )
    );

`ifdef VERILATOR
    initial $display("[%0t][DS_IF] Debug prints enabled (Verilator)", $time);
    integer dbg_cnt_ds;
    // Debug: observe AR IDs leaving the DS IF and R IDs returning
    always_ff @(posedge clk_i) begin
        if (!rst_ni) dbg_cnt_ds <= 0;
        else dbg_cnt_ds <= dbg_cnt_ds + 1;

        if (cq_req_i.ar_valid) begin
            $display("[%0t][DS_IF] CQ ar_valid=1 id=0x%0h", $time, cq_req_i.ar.id);
        end
        if (ds_req_o.ar_valid) begin
            $display("[%0t][DS_IF] AR asserted id=0x%0h ready=%0b", $time, ds_req_o.ar.id, ds_resp_i.ar_ready);
        end
        if (ds_resp_i.r_valid && ds_resp_i.r.last) begin
            $display("[%0t][DS_IF] R last id=0x%0h demux_sel=%0d ready=%0b", $time, ds_resp_i.r.id, r_select, ds_req_o.r_ready);
        end
        if (dbg_cnt_ds < 16 && !ds_req_o.ar_valid && !cq_req_i.ar_valid) begin
            $display("[%0t][DS_IF] AR idle ptw=%0b cdw=%0b cq=%0b ready=%0b", $time, ptw_req_i.ar_valid, cdw_req_i.ar_valid, cq_req_i.ar_valid, ds_resp_i.ar_ready);
        end
        if (cq_req_i.aw_valid) begin
            $display("[%0t][DS_IF] CQ aw_valid=1 id=0x%0h addr=0x%0h",
                     $time, cq_req_i.aw.id, cq_req_i.aw.addr);
        end
        if (ds_req_o.aw_valid) begin
            $display("[%0t][DS_IF] DS aw_valid=1 id=0x%0h addr=0x%0h ready=%0b",
                     $time, ds_req_o.aw.id, ds_req_o.aw.addr, ds_resp_i.aw_ready);
        end
    end
`endif
    
endmodule
